import{_ as e,a as i,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o as s,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Authentication dan Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Safety/authentication-and-login-devices.md","filePath":"ms-MY/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"ms-MY/Safety/authentication-and-login-devices.md"};function r(u,a,m,c,p,g){return s(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="authentication-dan-login-device-management" tabindex="-1">Authentication dan Login Device Management <a class="header-anchor" href="#authentication-dan-login-device-management" aria-label="Permalink to &quot;Authentication dan Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> dan <code>Login Device Management</code> melindungi ImgBed admin panel, public upload entry dan WebDAV access.</p><p>Gunakan halaman ini untuk menetapkan access credentials, menyemak devices yang sudah sign in dan revoke sessions lama apabila perlu.</p><h2 id="di-mana-untuk-configure" tabindex="-1">Di Mana Untuk Configure <a class="header-anchor" href="#di-mana-untuk-configure" aria-label="Permalink to &quot;Di Mana Untuk Configure&quot;">​</a></h2><p>Buka admin panel, kemudian pergi ke:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>Halaman ini mempunyai dua bahagian utama:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+e+'" alt="Authentication management" loading="lazy"></p><h2 id="fungsi-authentication-management" tabindex="-1">Fungsi Authentication Management <a class="header-anchor" href="#fungsi-authentication-management" aria-label="Permalink to &quot;Fungsi Authentication Management&quot;">​</a></h2><p>Authentication Management menyimpan access credentials.</p><p>Terdapat dua jenis:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication ialah upload password.</p><p>Selepas upload password ditetapkan, visitors biasa mesti memasukkannya sebelum menggunakan upload page. Ini berguna apabila anda tidak mahu public upload page terbuka kepada semua orang.</p><p><img src="'+i+'" alt="User login page" loading="lazy"></p><h3 id="menetapkan-upload-password" tabindex="-1">Menetapkan Upload Password <a class="header-anchor" href="#menetapkan-upload-password" aria-label="Permalink to &quot;Menetapkan Upload Password&quot;">​</a></h3><p>Apabila upload password dikonfigurasi:</p><ul><li>Visitors mesti memasukkan password sebelum menggunakan upload page.</li><li>Upload hanya tersedia selepas password diterima.</li><li>Jika user-side device sessions diaktifkan, ImgBed akan merekod user-side device tersebut.</li></ul><p>Menukar upload password akan menjadikan user-side sessions lama invalid. Visitors perlu memasukkan password baharu semula.</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication menggunakan admin username dan password.</p><p>Ini melindungi admin panel. Untuk production use, anda patut sentiasa configure bahagian ini.</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="menetapkan-admin-credentials" tabindex="-1">Menetapkan Admin Credentials <a class="header-anchor" href="#menetapkan-admin-credentials" aria-label="Permalink to &quot;Menetapkan Admin Credentials&quot;">​</a></h3><p>Apabila admin username dan password dikonfigurasi:</p><ul><li>Admin panel memerlukan login sebelum boleh dibuka.</li><li>Login yang berjaya mencipta admin device record.</li><li>Anda boleh review, clean up atau force devices offline dalam Login Device Management.</li></ul><p>Menukar admin username atau password akan menjadikan admin sessions lama invalid. Anda perlu sign in semula.</p><h2 id="fungsi-login-device-management" tabindex="-1">Fungsi Login Device Management <a class="header-anchor" href="#fungsi-login-device-management" aria-label="Permalink to &quot;Fungsi Login Device Management&quot;">​</a></h2><p>Login Device Management memaparkan devices yang pernah sign in.</p><p>Ia membantu menyemak:</p><ul><li>Devices mana yang mengakses admin panel.</li><li>Devices mana yang mengakses user-side upload page.</li><li>WebDAV clients mana yang connected.</li><li>Sama ada device session masih valid.</li><li>Sama ada devices lama perlu force offline.</li></ul><p>Halaman ini mempunyai tiga tabs:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>Di bahagian atas Login Device Management, anda boleh configure global cookie behavior.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>Mengawal berapa hari user-side login boleh kekal active.</p><p>Contohnya, jika ditetapkan kepada 14 days, visitors biasanya tidak perlu memasukkan upload password semula dalam tempoh 14 hari.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>Mengawal berapa hari admin login boleh kekal active.</p><p>Contohnya, jika ditetapkan kepada 14 days, administrators biasanya tidak perlu sign in semula dalam tempoh 14 hari.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Apabila Secure mode diaktifkan, browsers hanya menghantar login cookies melalui HTTPS.</p><p>Aktifkan untuk production HTTPS sites. Jangan aktifkan untuk local HTTP testing, jika tidak anda mungkin melihat keadaan &quot;login berjaya, tetapi refresh membuatkan saya logout&quot;.</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab memaparkan devices yang sign in ke admin panel.</p><p>Device records hanya muncul selepas admin credentials dikonfigurasi dan admin panel diakses melalui login.</p><p>Setiap device card boleh memaparkan:</p><ul><li>Device dan browser information</li><li>First login IP</li><li>Last active IP</li><li>Login time</li><li>Last active time</li><li>Expiration time</li><li>Current status</li></ul><p>Jika anda melihat device yang tidak dikenali, gunakan <code>Force Offline</code> untuk menjadikannya invalid.</p><h2 id="clean-up-old-devices" tabindex="-1">Clean Up Old Devices <a class="header-anchor" href="#clean-up-old-devices" aria-label="Permalink to &quot;Clean Up Old Devices&quot;">​</a></h2><p><code>Clean Up Old Devices</code> membuang login records lama dalam tab semasa secara bulk.</p><p>Gunakan apabila anda mengesyaki sessions lama mungkin masih active pada devices lain.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> menjadikan satu device session invalid.</p><p>Selepas device dipaksa offline:</p><ul><li>Admin devices mesti sign in semula.</li><li>User-side devices mesti memasukkan upload password semula.</li><li>WebDAV clients mesti authenticate semula.</li></ul><p>Expired atau invalid devices juga boleh dibuang.</p><h2 id="sign-out-current-device" tabindex="-1">Sign Out Current Device <a class="header-anchor" href="#sign-out-current-device" aria-label="Permalink to &quot;Sign Out Current Device&quot;">​</a></h2><p>Current device card ditanda sebagai <code>Current Device</code>.</p><p>Selepas sign out current device:</p><ul><li>Current admin session akan sign out.</li><li>Current user-side session akan sign out.</li></ul><p>Anda perlu sign in semula sebelum terus menggunakan bahagian tersebut.</p>',65)])])}const v=t(d,[["render",r]]);export{b as __pageData,v as default};
